import{_ as a,o as s,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"25. Salary","description":"","frontmatter":{"title":"25. Salary","eba":"Nurses and Midwives 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/wages/25-salary.md","filePath":"ebas/nurses-midwives/wages/25-salary.md"}'),n={name:"ebas/nurses-midwives/wages/25-salary.md"};function o(p,e,l,i,c,d){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_25-salary" tabindex="-1">25. Salary <a class="header-anchor" href="#_25-salary" aria-label="Permalink to &quot;25. Salary&quot;">​</a></h1><p><strong>25.1</strong> The rates of pay applicable to Employees upon commencement of the Agreement are set out in the applicable column of the table in Part 1 of <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>.</p><p><strong>25.2</strong> Employee rates of pay will increase over the life of this Agreement from the following dates in accordance with Part 1 of <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>:</p><p><strong>(a)</strong> 15 June 2024;</p><p><strong>(b)</strong> FFPPOOA 1 July 2024;</p><p><strong>(c)</strong> FFPPOOA 12 May 2025;</p><p><strong>(d)</strong> 29 November 2025;</p><p><strong>(e)</strong> FFPPOOA 11 May 2026;</p><p><strong>(f)</strong> 30 November 2026;</p><p><strong>(g)</strong> FFPPOOA 10 May 2027; and</p><p><strong>(h)</strong> 29 November 2027.</p><p><strong>25.3</strong> The calculation of the above percentages shall be made to the nearest 10 cents with any amount of 5 cents to be rounded up.</p>',12)])])}const h=a(n,[["render",o]]);export{m as __pageData,h as default};
